#include <bits/stdc++.h>
using namespace std;
string ans="0",s,s2;
int n;
string mx(string x,string y)
{
	if(x.size()==y.size())
	{
		if(x>y) return x;
		return y;
	}
	if(x.size()>y.size()) return x;
	return y;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>s;
		s2=s;
		reverse(s2.begin(),s2.end());
		if(s==s2)
		{
			ans=mx(ans,s);
		}
	}
	cout<<ans;
	return 0;
}
